    51→void RpcStream::bindDomainSocket(uint64_t id, const std::string& role,
    52→                                 const std::string& socket_path, mode_t socket_mode) {
    53→  Api::OsSysCalls& os_sys_calls = Api::OsSysCallsSingleton::get();
    54→  // This actually creates the socket and binds it. We use the socket in datagram mode so we can
    55→  // easily read single messages.
    56→  domain_socket_ = socket(AF_UNIX, SOCK_DGRAM | SOCK_NONBLOCK, 0);
    57→  sockaddr_un address = createDomainSocketAddress(id, role, socket_path, socket_mode);
    58→  unlink(address.sun_path);
    59→  Api::SysCallIntResult result =
    60→      os_sys_calls.bind(domain_socket_, reinterpret_cast<sockaddr*>(&address), sizeof(address));
    61→  if (result.return_value_ != 0) {
    62→    const auto msg = fmt::format(
    63→        "unable to bind domain socket with base_id={}, id={}, errno={} (see --base-id option)",
    64→        base_id_, id, result.errno_);
    65→    if (result.errno_ == SOCKET_ERROR_ADDR_IN_USE) {
    66→      throw HotRestartDomainSocketInUseException(msg);
    67→    }
    68→    throw EnvoyException(msg);
    69→  }
    70→}
