   162→// Pull the cloned fd, if present, out of the control data and write it into the
   163→// PassListenSocketReply proto; the higher level code will see a listening fd that Just Works. We
   164→// should only get control data in a PassListenSocketReply, it should only be the fd passing type,
   165→// and there should only be one at a time. Crash on any other control data.
   166→void RpcStream::getPassedFdIfPresent(HotRestartMessage* out, msghdr* message) {
   167→  // NOLINTNEXTLINE(clang-analyzer-core.UndefinedBinaryOperatorResult)
   168→  cmsghdr* cmsg = CMSG_FIRSTHDR(message);
   169→  if (cmsg != nullptr) {
   170→    RELEASE_ASSERT(cmsg->cmsg_level == SOL_SOCKET && cmsg->cmsg_type == SCM_RIGHTS &&
   171→                       replyIsExpectedType(out, HotRestartMessage::Reply::kPassListenSocket),
   172→                   "recvmsg() came with control data when the message's purpose was not to pass a "
   173→                   "file descriptor.");
   174→
   175→    out->mutable_reply()->mutable_pass_listen_socket()->set_fd(
   176→        *reinterpret_cast<int*>(CMSG_DATA(cmsg)));
   177→
   178→    RELEASE_ASSERT(CMSG_NXTHDR(message, cmsg) == nullptr,
   179→                   "More than one control data on a single hot restart recvmsg().");
   180→  }
   181→}
